import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { motion } from 'framer-motion';
import { yfinanceService, StockData } from '../services/yfinanceService';

const AdminContainer = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem;
`;

const PageHeader = styled.div`
  margin-bottom: 3rem;
  text-align: center;
`;

const Title = styled.h1`
  font-size: 2.5rem;
  background: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  margin-bottom: 1rem;
`;

const Section = styled.div`
  background: rgba(255, 255, 255, 0.05);
  backdrop-filter: blur(10px);
  border-radius: 20px;
  padding: 2rem;
  margin-bottom: 2rem;
  border: 1px solid rgba(255, 255, 255, 0.1);
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  margin-bottom: 1.5rem;
  color: #00f2fe;
`;

const Form = styled.form`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const FormGroup = styled.div`
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
`;

const Label = styled.label`
  font-size: 0.9rem;
  color: rgba(255, 255, 255, 0.6);
`;

const Input = styled.input`
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.1);
  padding: 0.8rem;
  border-radius: 10px;
  color: white;
  font-size: 1rem;

  &:focus {
    outline: none;
    border-color: #00f2fe;
  }
`;

const Select = styled.select`
  background: rgba(0, 0, 0, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.1);
  padding: 0.8rem;
  border-radius: 10px;
  color: white;
  font-size: 1rem;

  &:focus {
    outline: none;
    border-color: #00f2fe;
  }

  option {
    background: #1a1a1a;
  }
`;

const Button = styled.button<{ variant?: 'primary' | 'danger' }>`
  background: ${props => props.variant === 'danger' 
    ? 'linear-gradient(135deg, #ff6b6b 0%, #ee5253 100%)' 
    : 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)'};
  color: ${props => props.variant === 'danger' ? 'white' : 'black'};
  border: none;
  padding: 0.8rem 1.5rem;
  border-radius: 10px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.3s ease;
  margin-top: ${props => props.variant === 'primary' ? '1.5rem' : '0'};

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
`;

const StockList = styled.div`
  display: grid;
  gap: 1rem;
`;

const StockItem = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem;
  background: rgba(255, 255, 255, 0.03);
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.05);
`;

const StockInfo = styled.div`
  display: flex;
  gap: 2rem;
  align-items: center;
`;

const Symbol = styled.span`
  font-weight: 800;
  color: #00f2fe;
  min-width: 100px;
`;

const Name = styled.span`
  color: white;
  opacity: 0.9;
`;

const SectorTag = styled.span`
  font-size: 0.8rem;
  padding: 0.2rem 0.6rem;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 20px;
  text-transform: uppercase;
`;

const AdminEdit: React.FC = () => {
  const [stocks, setStocks] = useState<StockData[]>([]);
  const [loading, setLoading] = useState(true);
  const [newStock, setNewStock] = useState({
    symbol: '',
    name: '',
    sector: 'it',
    current_price: 100
  });

  const sectors = [
    'it', 'banking', 'automobile', 'energy', 'pharma', 
    'fmcg', 'metals', 'finance', 'hospitality', 'realty', 'us_stocks'
  ];

  useEffect(() => {
    loadStocks();
  }, []);

  const loadStocks = async () => {
    setLoading(true);
    const data = await yfinanceService.getAllStocks();
    setStocks(data);
    setLoading(false);
  };

  const handleAddStock = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newStock.symbol || !newStock.sector) return;

    const success = await yfinanceService.addStock(newStock);
    if (success) {
      setNewStock({ symbol: '', name: '', sector: 'it', current_price: 100 });
      loadStocks();
    }
  };

  const handleRemoveStock = async (symbol: string) => {
    if (window.confirm(`Are you sure you want to remove ${symbol}?`)) {
      const success = await yfinanceService.removeStock(symbol);
      if (success) {
        loadStocks();
      }
    }
  };

  return (
    <AdminContainer>
      <PageHeader>
        <Title>Edit Stock Database</Title>
        <p>Manage stocks available across the application</p>
      </PageHeader>

      <Section>
        <SectionTitle>Add New Stock</SectionTitle>
        <Form onSubmit={handleAddStock}>
          <FormGroup>
            <Label>Symbol</Label>
            <Input 
              type="text" 
              placeholder="e.g. AAPL or INFY.NS" 
              value={newStock.symbol}
              onChange={(e) => setNewStock({...newStock, symbol: e.target.value})}
              required
            />
          </FormGroup>
          <FormGroup>
            <Label>Name (Optional)</Label>
            <Input 
              type="text" 
              placeholder="e.g. Apple Inc." 
              value={newStock.name}
              onChange={(e) => setNewStock({...newStock, name: e.target.value})}
            />
          </FormGroup>
          <FormGroup>
            <Label>Sector</Label>
            <Select 
              value={newStock.sector}
              onChange={(e) => setNewStock({...newStock, sector: e.target.value})}
            >
              {sectors.map(s => (
                <option key={s} value={s}>{s.toUpperCase()}</option>
              ))}
            </Select>
          </FormGroup>
          <FormGroup>
            <Label>Initial Price</Label>
            <Input 
              type="number" 
              value={newStock.current_price}
              onChange={(e) => setNewStock({...newStock, current_price: Number(e.target.value)})}
            />
          </FormGroup>
          <Button type="submit" variant="primary">Add Stock</Button>
        </Form>
      </Section>

      <Section>
        <SectionTitle>Existing Stocks</SectionTitle>
        {loading ? (
          <p>Loading stocks...</p>
        ) : (
          <StockList>
            {stocks.map((stock) => (
              <StockItem key={stock.symbol}>
                <StockInfo>
                  <Symbol>{stock.symbol}</Symbol>
                  <Name>{stock.name}</Name>
                  <SectorTag>{stock.sector}</SectorTag>
                </StockInfo>
                <Button 
                  variant="danger" 
                  onClick={() => handleRemoveStock(stock.symbol)}
                >
                  Remove
                </Button>
              </StockItem>
            ))}
            {stocks.length === 0 && <p>No stocks found in the database. Visit a sector page to seed initial data.</p>}
          </StockList>
        )}
      </Section>
    </AdminContainer>
  );
};

export default AdminEdit;
